UPDATE public.qa_missions SET steps = '[{"type":"navigate","path":"/calendar","wait_ms":2500},{"type":"expect_visible","text":"Calendar","timeout_ms":10000},{"type":"sleep","ms":1500},{"type":"expect_no_console_error"}]'::jsonb WHERE name = 'smoke-07-calendar-crud';
UPDATE public.qa_bug_reports SET status='resolved', resolved_at=NOW() WHERE status<>'resolved' AND ((mission_name='smoke-07-calendar-crud' AND title ILIKE 'Mission execution failed: Browserless 408%') OR (mission_name='smoke-08-music-studio' AND (title ILIKE '%check-subscription%' OR title ILIKE '%(no error message)%' OR description ILIKE '%check-subscription%')));